  ('elementary-f29af906-moex-00140', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '下列有關地上權之敘述，何者錯誤？', '["地上權人不得將其權利設定抵押權", "在他人土地上下之一定空間範圍內設定之地上權，稱為區分地上權", "地上權人積欠地租達2年之總額，除另有習慣外，地上權人不於期限內支付，土地所有人得終止地上權", "土地及其土地上之建築物，同屬於一人所有，因強制執行之拍賣，其土地與建築物之拍定人各異時，視 為已有地上權之設定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
